// // This module selects an input signal based on the select lines
// When sel1 and sel0 are both low, the output will be in3;
// sel0 high and sel1 low selects in2;
// sel1 low and sel0 high selects in1;
// and when both select lines are high, in0 is chosen as the output.
module top_module(
    input in0,
    input in1,
    input in2,
    input in3,
    input sel0,
    input sel1,
    output out
);// Select the output based on the select lines
assign out = (sel1 & sel0) ? in3 : (sel1 & ~sel0) ? in2 : (~sel1 & sel0) ? in1 : in0;

endmodule

